import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class AdminService {
  private http = inject(HttpClient);
  private apiUrl = 'http://localhost:3000/api/admin';

  // 📊 Récupérer les compteurs du tableau de bord
  getDashboardStats(): Observable<any> {
    return this.http.get<any>(`${this.apiUrl}/dashboard-stats`);
  }

  // 👥 Récupérer tous les candidats et recruteurs
  getAllUsers(): Observable<any[]> {
    return this.http.get<any[]>(`${this.apiUrl}/users`);
  }

  // 🚫 Supprimer un utilisateur définitivement
  deleteUser(userId: number): Observable<any> {
    return this.http.delete<any>(`${`${this.apiUrl}/users`}/${userId}`);
  }

  // 💼 Récupérer l'intégralité des offres d'emploi en Tunisie
  getAllJobs(): Observable<any[]> {
    return this.http.get<any[]>(`${this.apiUrl}/jobs`);
  }

  // 🗑️ Supprimer une offre d'emploi non conforme
  deleteJob(jobId: number): Observable<any> {
    return this.http.delete<any>(`${`${this.apiUrl}/jobs`}/${jobId}`);
  }
}
